import { BackDropBottom, Button, Text } from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Dimensions } from 'react-native';

interface PointsInfoBottomSheetProps {
  modalizeRef: React.RefObject<PropsModalizeRef>;
}

const PointsInfoBottomSheet: FC<PointsInfoBottomSheetProps> = ({ modalizeRef }) => {
  const { height } = Dimensions.get('window');
  return (
    <BackDropBottom modalHeight={height * 0.3} modalizeRef={modalizeRef}>
      <Text type="paragraphMD" align="center" color="INTENSE_COLOR_05" mt="small" mb="smaller">
        Os seus pontos ganhos ficam disponíveis no saldo sempre que você pagar sua próxima fatura.
      </Text>
      <Button text="Entendi" onPress={() => modalizeRef.current?.close?.()} />
    </BackDropBottom>
  );
};
export default PointsInfoBottomSheet;
```

## Questions to answer:
1. Is the mock correctly structured (forwardRef, useImperativeHandle, __esModule)?
2. Does the mock scope (file-level) avoid affecting other tests?
3. Is this the right approach for testing modal-wrapped components?
4. Are there any correctness issues with the mock implementation?
5. Could this fix mask real bugs or break the test's intent?

Provide your review verdict: APPROVE or REQUEST_CHANGES with details.

