import React from 'react';

import { Box } from '../Box';
import Modalize from '../Modalize/view';
import { PropsBackDropBottom } from './Models';

function BackDropBottom({
  modalizeRef,
  children,
  modalHeight,
  adjustToContentHeight = !modalHeight,
  withHandle = true,
  onBackButtonPress,
  onClose,
  testID,
  HeaderComponent,
  scrollEnabled = true,
  pd = 'innerLarger',
}: PropsBackDropBottom) {
  return (
    <Modalize
      bgColor="INTENSE_COLOR_01"
      showHeaderHandle={withHandle}
      ref={modalizeRef}
      adjustToContentHeight={adjustToContentHeight}
      scrollEnabled={scrollEnabled}
      onBackButtonPress={onBackButtonPress}
      onClose={onClose}
      height={modalHeight}
      HeaderComponent={HeaderComponent}
      pd={pd === 'innerLarger' ? 'innerLarger' : 'none'}
    >
      <Box
        testID={testID}
        borderRadiusTopLeft="half"
        borderRadiusTopRight="half"
        width="100%"
        height="100%"
      >
        {children}
      </Box>
    </Modalize>
  );
}
export default BackDropBottom;

